```go
type registerSameEvent struct {
    goal *resource.Goal
}

func newRegisterSameEvent(state *resource.State) RegisterResourceEvent {
    goal := // create a new goal using the values in `state`
    return &registerSameEvent{goal}
}

func (e registerSameEvent) event() {}

func (e registerSameEvent) Goal() *resource.Goal {
    return e.goal
}

func (e registerSameEvent) Done(_ *RegisterResult) {}
```

